// index.js
import fetch from 'node-fetch';
import cheerio from 'cheerio';
import { AbortController } from 'abort-controller';

const DEFAULT_TIMEOUT_MS = 7000;

function isValidHttpUrl(string) {
  try {
    const url = new URL(string);
    return url.protocol === 'http:' || url.protocol === 'https:';
  } catch (_) {
    return false;
  }
}

async function fetchHtml(url) {
  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), DEFAULT_TIMEOUT_MS);
  const res = await fetch(url, {
    headers: { 'User-Agent': 'MetadataBot/1.0 (+https://example.com)' },
    signal: controller.signal,
    redirect: 'follow'
  });
  clearTimeout(timeout);
  if (!res.ok || !res.headers.get('content-type')?.includes('text/html')) {
    throw new Error('Invalid response');
  }
  return res.text();
}

function extractMetadata(html) {
  const $ = cheerio.load(html);

  const getMeta = (property, attr = 'property') =>
    $(`meta[${attr}="${property}"]`).attr('content') ||
    $(`meta[name="${property}"]`).attr('content') ||
    undefined;

  const ogTags = {};
  [
    'og:title',
    'og:description',
    'og:image',
    'og:url',
    'og:site_name',
    'og:type'
  ].forEach(tag => {
    const value = getMeta(tag);
    if (value) ogTags[tag] = value;
  });

  const title =
    getMeta('title', 'name') ||
    $('title').first().text().trim() ||
    ogTags['og:title'];

  const description =
    getMeta('description') ||
    ogTags['og:description'];

  return { title, description, openGraph: ogTags };
}

export const fetchMetadata = async (req, res) => {
  const targetUrl = req.query.url || req.body?.url;
  if (!targetUrl || !isValidHttpUrl(targetUrl)) {
    res.status(400).json({ error: 'Invalid or missing url parameter.' });
    return;
  }

  try {
    const html = await fetchHtml(targetUrl);
    const metadata = extractMetadata(html);
    res.status(200).json(metadata);
  } catch (err) {
    res.status(500).json({ error: 'Failed to fetch metadata.', details: err.message });
  }
};